283→    State(pool): State<PgPool>,
284→    headers: HeaderMap,
285→    Path(todo_id): Path<Uuid>,
286→    Form(form): Form<EditTodoForm>,
287→) -> Result<Response, TodosError> {
288→    let htmx = is_htmx_request(&headers);
289→    let todo_item_id = TodoItemId::from_uuid(todo_id);
290→
291→    match update_todo_title(&pool, &todo_item_id, &user_id, form.title.clone()).await {
292→        Ok(()) => {
293→            if htmx {
