 2→use axum::extract::State;
 3→use axum::http::StatusCode;
 4→use axum::response::{Html, IntoResponse, Redirect, Response};
 5→use axum::Form;
 6→use sqlx::PgPool;
 7→use tower_sessions::Session;
 8→
 9→use crate::services::authentication::{authenticate_user, AuthenticationError};
10→
11→#[derive(Template)]
12→#[template(path = "login.html")]
13→pub struct LoginTemplate {
14→    pub error_message: Option<String>,
15→    pub form_email: String,
16→}
17→
18→pub async fn get_login() -> Result<impl IntoResponse, LoginError> {
19→    let template = LoginTemplate {
20→        error_message: None,
21→        form_email: String::new(),
22→    };
23→    Ok(Html(template.render()?))
24→}
25→
26→#[derive(serde::Deserialize)]
27→pub struct LoginFormData {
28→    pub email: String,
29→    pub password: String,
30→}
31→
32→pub async fn post_login(
33→    State(pool): State<PgPool>,
34→    session: Session,
35→    Form(form): Form<LoginFormData>,
36→) -> Result<Response, LoginError> {
37→    match authenticate_user(&pool, form.email.clone(), form.password).await {
38→        Ok(user_id) => {
39→            session.cycle_id().await.map_err(|e| {
40→                LoginError::Session(anyhow::anyhow!("Failed to cycle session: {e}"))
41→            })?;
42→            session
43→                .insert("user_id", user_id.as_uuid().to_string())
44→                .await
