async fn index_redirects_authenticated_user_to_todos() {
    let app = spawn_app().await;

    let client = register_and_login(&app.address, "index@example.com", "securepassword123").await;

    let response = client
        .get(format!("{}/", &app.address))
        .send()
        .await
        .expect("Failed to execute request");

    assert_eq!(
        response.status().as_u16(),
        303,
        "Authenticated user should be redirected from index"
    );

    let location = response
        .headers()
        .get("location")
        .expect("Missing Location header")
        .to_str()
        .unwrap();
    assert_eq!(
        location, "/todos",
        "Authenticated user should be redirected to /todos"
    );
}

    let client = reqwest::Client::builder()
        .redirect(reqwest::redirect::Policy::none())
        .build()
        .unwrap();

    let response = client
        .post(format!("{}/login", &app.address))
        .form(&[("email", email), ("password", password)])
        .send()
        .await
        .expect("Failed to execute request");

    let status = response.status().as_u16();
    let location = response
        .headers()
        .get("location")
        .map(|v| v.to_str().unwrap().to_string());
    let body = response.text().await.unwrap();

    assert_eq!(
        status, 303,
        "Expected 303 redirect after successful login. Body: {body}"
    );
    assert_eq!(
        location.as_deref(),
        Some("/todos"),
        "Should redirect to /todos after login"
    );
}

